INSERT INTO questions (subject, exam_type, question, option_a, option_b, option_c, option_d, option_e, correct_answer, explanation, year) VALUES 
('english', 'WAEC', 'The posh cars were sandwiched between two _________ ones.', 'dented', 'rugged', 'rickety', 'modest', NULL, 'D', 'The word "posh" means elegant, luxurious, or stylish. The word "modest" means simple, humble, or unpretentious. These words are opposites in meaning.', 2023), 
('english', 'WAEC', 'A trivial issue often becomes _________ when it is not properly handled.', 'valuable', 'serious', 'unbearable', 'ordinary', NULL, 'B', 'The word "trivial" means insignificant, unimportant, or minor. The word serious means significant, important, or major.', 2023), 
('english', 'WAEC', 'The rockstar''s stellar performance contrasted sharply with the _________ showing of the amateur group.', 'routine', 'woeful', 'mundane', 'awkward', NULL, 'B', 'The word "stellar" means excellent or outstanding. The word that is most nearly opposite in meaning to "stellar" and correctly fills the gap is "woeful."', 2023), 
('english', 'WAEC', 'Tolu was sanctioned for late coming but his friend was _________.', 'pardoned', 'ignored', 'exempted', 'released', NULL, 'A', 'The word "sanctioned" in this context means that Tolu was punished or reprimanded for his late coming. The opposite of being punished or reprimanded would be to be forgiven or excused, which is the meaning of "pardoned."', 2023), 
('english', 'WAEC', 'While other teachers'' support for the action was Victor was _________, dogged.', 'declining', 'woeful', 'disappointing', 'wavering', NULL, 'D', 'The word "dogged" suggests that Victor''s support for the action was persistent or determined. The word that is most nearly opposite in meaning to "dogged" is "wavering," which means uncertain or indecisive.', 2023), 
('english', 'WAEC', 'Some people are good at terminating other people''s projects but are not capable of _________ theirs.', 'initiating', 'designing', 'organizing', 'executing', NULL, 'A', 'The word "terminating" suggests that some people are good at ending or stopping other people''s projects. The word most nearly opposite in meaning to "terminating" is "initiating," which means to start or begin.', 2023), 
('english', 'WAEC', 'The precarious terraces of the stadium have been transformed into a _________ walkway.', 'durable', 'secure', 'smooth', 'narrow', NULL, 'B', 'The word "precarious" means uncertain or unstable. The word nearly opposite to "precarious" is "secure." Therefore, the correct answer is B. secure.', 2023), 
('english', 'WAEC', 'If one thing irritates you, it might _________ another.', 'delight', 'concern', 'invigorate', 'bother', NULL, 'A', 'The word "irritates" means to annoy or make someone feel impatient. The word "delight" means to please or bring joy to someone.', 2023), 
('english', 'WAEC', 'Jane was loud as a teenager but _________ as an adult.', 'peaceful', 'reserved', 'humble', 'respectful', NULL, 'A', '"Peaceful" means calm, quiet, and not causing disturbance. "Reserved" means being quiet, restrained, or not openly expressing emotions or opinions. "Humble" means having a modest or low view of one''s importance or abilities.', 2023), 
('english', 'WAEC', 'Do not always reprimand your children; it is good to _________ them at times.', 'advise', 'forgive', 'compliment', 'pamper', NULL, 'C', 'The word "reprimand" means to scold or criticize someone for their actions. The word that is most nearly opposite in meaning to "reprimand" and correctly fills the gap in the sentence is "compliment."', 2023), 
('english', 'WAEC', 'The aggrieved customers staged a fierce _________ on the street.', 'fight', 'protest', 'argument', 'contest', NULL, 'B', 'When people are dissatisfied or angry about something, they often stage a protest to express their grievances and demand change. In this context, a protest on the street would indicate the customers are publicly demonstrating their dissatisfaction.', 2023), 
('english', 'WAEC', 'The accused was brought before the jury for a court _________.', 'sitting', 'judging', 'hearing', 'proceeding', NULL, 'C', 'A court hearing refers to a formal session in which a case is presented before a judge or jury. In this context, the accused is being brought before the jury for a court hearing.', 2023), 
('english', 'WAEC', 'From his _________, one can tell that he is an athlete.', 'physique', 'anatomy', 'stature', 'gait', NULL, 'A', 'Physique refers to the overall physical appearance and build of a person. It includes factors such as muscle tone, body shape, and overall fitness level. In the context of the sentence, it suggests that the person being described has a physical appearance typical of an athlete.', 2023), 
('english', 'WAEC', 'The death of that journalist is still _________ in mystery.', 'conveyed', 'shrouded', 'confined', 'shadowed', NULL, 'B', 'The word "shrouded" means covered or concealed, often implying a sense of mystery or secrecy. In the context of the sentence, it suggests that the circumstances surrounding the death of the journalist are still unknown or unclear.', 2023), 
('english', 'WAEC', 'The defendant was charged with _________ because he caused his neighbour''s death.', 'genocide', 'fratricide', 'parricide', 'homicide', NULL, 'D', 'Homicide refers to the act of causing someone''s death, which is the charge the defendant is facing in this case.', 2023), 
('english', 'WAEC', 'Seeing a young crop _________ from the soil is a rare experience.', 'trail', 'sprout', 'creep', 'project', NULL, 'B', 'The word "sprout" best fits this context because it specifically refers to the act of a plant or seed beginning to grow and emerge from the ground.', 2023), 
('english', 'WAEC', 'Lawyers are still making efforts to interpret the new _________.', 'language', 'technique', 'system', 'statute', NULL, 'D', 'A statute refers to a written law that has been formally enacted by a legislative body. In the context of the sentence, lawyers are trying to interpret a new statute, which means they are trying to understand and make sense of the provisions and requirements of the new law.', 2023), 
('english', 'WAEC', 'The cargo was intercepted on sea by _________.', 'pirates', 'thieves', 'terrorists', 'robbers', NULL, 'A', 'Pirates are individuals who engage in acts of robbery or violence at sea. They typically target ships and steal valuable cargo or take hostages for ransom. In this context, the word "intercepted" suggests that the cargo was seized or attacked by these pirates while it was on the sea.', 2023), 
('english', 'WAEC', 'The doctors _________ Bola''s grandmother after the heart attack.', 'resuscitated', 'generated', 'revivified', 'resurrected', NULL, 'A', 'To resuscitate someone means to revive or bring them back to life after they have stopped breathing or their heart has stopped. In this context, the doctors are likely trying to revive Bola''s grandmother after she had a heart attack.', 2023), 
('english', 'WAEC', 'Because the couple cannot agree on many things, their relationship is now _________.', 'stressed', 'uneasy', 'tensed', 'strained', NULL, 'D', 'The word "strained" is the best choice to complete the sentence because it accurately describes a relationship that is experiencing tension or difficulty due to disagreements.', 2023), 
('english', 'WAEC', 'Revealing that information will cut the ground from under my feet. This means it will:', 'expose my plans', 'ruin my plans', 'promote my plans', 'support my plans', NULL, 'B', 'The phrase "cut the ground from under my feet" is an idiom that means to undermine one''s position or plans. In this context, revealing the information would have a negative impact and cause one''s plans to fail or be ruined.', 2023), 
('english', 'WAEC', 'Mother always tells me to keep my nose clean. This means that she tells me to:', 'stay healthy', 'do what pleases me', 'stay out of trouble', 'be focused', NULL, 'C', 'The phrase "keep your nose clean" is an idiomatic expression that means to stay out of trouble or avoid getting involved in any wrongdoing or illegal activities.', 2023), 
('english', 'WAEC', 'This action effectively puts the mockers on the project. This means that the project will:', 'take off soon', 'not be executed', 'be delayed', 'not begin well', NULL, 'B', '"Put the mockers on something/somebody" means to stop something from happening or to bring bad luck to something/somebody.', 2023), 
('english', 'WAEC', 'You can see clearly that we are surpassed in numerical strength. This means:', 'we are stronger than they are', 'we are much weaker than they are', 'we are fewer than they are', 'we are as strong as they are', NULL, 'C', 'The sentence "You can see clearly that we are surpassed in numerical strength" implies that we have a smaller number of people or resources than they do.', 2023), 
('english', 'WAEC', 'One of the athletes was disqualified because she jumped the gun. This means:', 'she hurriedly won', 'she used a gun', 'she started too soon', 'she was disqualified', NULL, 'C', 'The idiom "jump the gun" means to act before the proper or appropriate time, especially without thinking carefully. The phrase "jumped the gun" in this context means that the athlete started too soon — she started the race before the starting pistol has been fired.', 2023), 
('english', 'WAEC', 'There are no flies on the boss. This means the boss is:', 'smart', 'hardworking', 'experienced', 'strict', NULL, 'A', 'The phrase "there are no flies on the boss" is an idiomatic expression that means the boss is smart or astute. It implies that the boss is quick-witted and not easily fooled or deceived.', 2023), 
('english', 'WAEC', 'The students cocked their ears at the principal''s speech. This means they listened with:', 'a little interest', 'rapt attention', 'no understanding', 'no interest', NULL, 'B', 'To "cock one''s ears" means to listen attentively or with great interest. Therefore, the most appropriate interpretation for the sentence is "rapt attention." The students were fully engaged and focused on the principal''s speech.', 2023), 
('english', 'WAEC', 'Your daughter will do very well in school. She has a good head on her shoulders. This means that she is:', 'intelligent', 'very beautiful', 'sensible', 'well-behaved and diligent', NULL, 'C', 'The phrase "has a good head on her shoulders" is an idiomatic expression that means someone is sensible, intelligent, and makes good decisions.', 2023), 
('english', 'WAEC', 'The accountant has been under a cloud since the fraud scandal. This means that the accountant is:', 'worried', 'under supervision', 'unhappy', 'under suspicion', NULL, 'D', 'Being "under a cloud" typically means being under suspicion or having a negative reputation due to some wrongdoing or scandal.', 2023), 
('english', 'WAEC', 'Immediately the truth was revealed, Ngozi flew into a rage. This means that Ngozi:', 'suddenly became very angry', 'became sad', 'became desperate', 'was surprised', NULL, 'A', 'The sentence states that "immediately the truth was revealed, Ngozi flew into a rage." This means that Ngozi became very angry right after the truth was revealed.', 2023), 
('english', 'WAEC', 'Parents encourage their children to exercise financial prudence. "Prudence" means:', 'caution', 'sincerity', 'credence', 'precision', NULL, 'A', 'The word "prudence" /pru:dns/ in the sentence means carefulness or caution in managing finances. Therefore, the word or group of words nearest in meaning to "prudence" is "caution."', 2023), 
('english', 'WAEC', 'Awa deceived Ahmed into handing over all his savings. "Deceived" means:', 'fooled', 'cheated', 'cooked', 'conned', NULL, 'A', 'In this sentence, the word "deceived" means to trick or mislead someone. The word nearest in meaning to "deceived" is "fooled."', 2023), 
('english', 'WAEC', 'It turned out that the plaintiff''s claim was false. "Allegation" means:', 'surmise', 'contention', 'pronouncement', 'allegation', NULL, 'C', 'This means that the assertion or accusation that was found to be false is an "allegation."', 2023), 
('english', 'WAEC', 'The aggrieved faction held a clandestine meeting. "Clandestine" means:', 'quiet', 'secret', 'brief', 'organized', NULL, 'B', 'To hold a clandestine meeting means to hold a secret meeting, where the purpose or details are not meant to be known by others. Therefore, the word "secret" (option A) is the word nearest in meaning to "clandestine" in this sentence.', 2023), 
('english', 'WAEC', 'Morgan Pharmacy is the sole distributor of the antiviral drug. "Sole" means:', 'creditable', 'major', 'only', 'first', NULL, 'C', 'In this sentence, the word "sole" means "only." It emphasizes that Morgan Pharmacy is the exclusive distributor of the antiviral drug, implying that no other distributor is involved.', 2023), 
('english', 'WAEC', 'Police officers holding batons impounded the banker''s car. "Impounded" means:', 'damaged', 'seized', 'banned', 'collected', NULL, 'B', 'To seize something means to take possession of it forcefully or legally. In this sentence, the police officers took possession of the banker''s car, so the word "seized" is the closest in meaning to "impounded."', 2023), 
('english', 'WAEC', 'The English teacher is always cheerful. "Gleeful" means:', 'satisfied', 'zealous', 'gleeful', 'careful', NULL, 'C', 'In this sentence, the word "cheerful" means happy or in a good mood. Among the options provided, the word that is closest in meaning to "cheerful" is "gleeful."', 2023), 
('english', 'WAEC', 'The Chairman is of the opinion that laying off workers is pernicious to the growth of the company. "Pernicious" means:', 'harmful', 'relevant', 'indispensable', 'crucial', NULL, 'A', 'The word "pernicious" means causing great harm or damage. Therefore, the word that nearest in meaning to "pernicious" in this sentence is "harmful."', 2023), 
('english', 'WAEC', 'It was she that commanded me to leave the room. "Ordered" means:', 'encouraged', 'persuaded', 'induced', 'commanded', NULL, 'D', 'In this sentence, the word "commanded" means that she gave a direct order or instruction for the speaker to leave the room.', 2023), 
('english', 'WAEC', 'The valedictorian was admired for her perseverance while at school. "Tenacity" means:', 'patience', 'humility', 'enthusiasm', 'tenacity', NULL, 'D', 'Tenacity refers to the quality of being determined and persistent in achieving a goal or completing a task. In the given sentence, the valedictorian is admired for her perseverance, which implies that she has shown determination and persistence in her studies and activities while at school. Therefore, the word "tenacity" is the closest in meaning to the underlined word "perseverance" in this context.', 2023), 
('english', 'WAEC', 'The fisherman said he sighted a _________ of fish in the river.', 'pack', 'Swarm', 'shoal', 'colony', NULL, 'C', 'A shoal /fʃʌl/ is a group of fish swimming together. It is a common term used to describe a large number of fish swimming together in a particular area.', 2023), 
('english', 'WAEC', 'The principal corrected no one else but _________.', 'me', 'I', 'she', 'myself', NULL, 'A', 'In this sentence, the objective case of the first-person singular pronoun should be used after the preposition "but." The objective form is "me," which is the appropriate choice in this context.', 2023), 
('english', 'WAEC', 'The thug was _________ murder.', 'sued', 'charged with', 'convicted for', 'charged for', NULL, 'B', '"When someone is charged with murder," it means that they have been formally accused of committing the crime of murder. The word "charged" here refers to the legal action taken by authorities to accuse someone of a crime.', 2023), 
('english', 'WAEC', 'Asokoro office _________ is located in Ibadan.', 'headquarter', 'headquarters', 'headquarters', 'headquarter''s', NULL, 'B', 'The word "headquarters" is a noun that refers to the main office or company location of an organization or company. In this case, we are talking about the headquarters of the Asokoro office.', 2023), 
('english', 'WAEC', 'John should be through with his work by now, ________?', 'isn''t it', 'shouldn''t he', 'can''t he', 'didn''t he', NULL, 'B', 'The phrase "shouldn''t he" is asking for confirmation or agreement with the statement that John should be through with his work. The phrase "shouldn''t he" is used to seek agreement or confirmation in a question form.', 2023), 
('english', 'WAEC', 'This is the man _________ I said told me the interesting story.', 'who', 'whom', 'whose', 'which', NULL, 'A', '"Who" introduces a relative clause that gives more information about a person. In this sentence, the relative pronoun is used as the subject of the second clause. "Who" is used to qualify a noun in the subject position, but "whom" describes a noun in object position.', 2023), 
('english', 'WAEC', 'The accused forgot _________ the police said.', 'what', 'that the police said', 'when the police said', 'which', NULL, 'A', '"What" is the appropriate relative pronoun in this sentence that functions as object of the verb said so we use "what" which introduces a noun clause and acts as an object.', 2023), 
('english', 'WAEC', 'The officer _________ is my brother.', 'on uniform', 'with uniform', 'in uniform', 'in uniform dress', NULL, 'C', '"In" is the appropriate preposition to describe the officer''s state or condition of being in a uniform. "In" is used to indicate being inside or within something.', 2023), 
('english', 'WAEC', 'The footballers have been practicing hard _________ in the stadium all morning.', 'in the stadium all', 'hard in the stadium all', 'all morning in the stadium', 'hard in the stadium all morning', NULL, 'B', '"Hard in the stadium all morning" is the answer choice that correctly places the adverb "hard" and the prepositional phrase "in the stadium" before the noun phrase "all morning."', 2023), 
('english', 'WAEC', 'Professor John is the leader of the new _________ committee to review the book.', 'fifty-man', 'fifty-men''s', 'fifty-men', 'fifty-men''s', NULL, 'A', '"Fifty-man" is a compound adjective that modifies the noun committee. A compound adjective to describe that act as a single adjective consists of two or more words joined by a hyphen.', 2023), 
('english', 'WAEC', 'James appears _________ wiser than his friends.', 'more', 'most', 'much', 'very', NULL, 'C', '"Much" is an adverb that modifies the comparative adjective wiser. An adverb is a word that modifies a verb, an adjective, or another adverb by answering questions such as how, when, where, why, or to what degree.', 2023), 
('english', 'WAEC', 'That world famous athlete is guilty, _________ way you look at it.', 'whichever', 'however', 'whatever', 'whenever', NULL, 'A', '"Whichever" is the correct relative pronoun used to introduce a relative clause that gives additional information about a noun or pronoun.', 2023), 
('english', 'WAEC', 'We were all afraid when the alarm went off.', 'rang up', 'rang out', 'rang off', 'rang', NULL, 'B', '"Went off" is the correct answer because it is used to describe the action of an alarm sounding or activating. When an alarm "goes off," it means that it has started making noise or has been triggered.', 2023), 
('english', 'WAEC', 'The Chairman wasn''t privy _________ that information.', 'to', 'about', 'of', 'for', NULL, 'A', 'The phrase "privy to" means to be allowed to know about something secret or private. So, the sentence should read: "The Chairman wasn''t privy to that information."', 2023), 
('english', 'WAEC', 'We were lucky our driver didn''t die in the accident, ________?', 'weren''t we', 'didn''t we', 'were we', 'did we', NULL, 'A', 'The verb of the sentence should be the basis for creating the tag. The verb is "were", promised, for emphatic purpose. The statement is positive, so by rule of question tag we expect a negative tag.', 2023), 
('english', 'WAEC', 'Before the lecturer entered the hall, the board _________.', 'was cleaned', 'has been cleaned', 'had cleaned', 'had been cleaned', NULL, 'D', 'This is because the sentence is in the past tense, indicating that the action of cleaning the board occurred before the lecturer entered the hall. The past perfect tense "had cleaned" is used to show that the action of cleaning the board was completed before another past action (the lecturer entering the hall) took place.', 2023);
